import React, { useContext } from "react";
import "../styles/Home.css";
import { ThemeContext } from "../context/ThemeContext";

const Home = () => {
    const { theme } = useContext(ThemeContext);

    return (
        <section className={`home-container ${theme}`}>

            <div className="hero-section">
                <h1>
                    Your business deserves <br /> <span>modern software</span>
                </h1>
                <p>
                    ActAware helps people learn sign language in a faster, more efficient way—
                    no barriers to understanding.
                </p>
                <div className="hero-buttons">
                    <button className="build-btn">Build for me</button>
                    <button className="start-btn">Start learning</button>
                </div>
            </div>
        </section>
    );
};

export default Home;
